{"code": "import json

# Load all 2015 article metadata
with open('file_storage/functions.query_db:14.json', 'r') as f:
    metadata_2015 = json.load(f)

# Create region lookup
region_lookup = {int(item['article_id']): item['region'] for item in metadata_2015}
all_article_ids = list(region_lookup.keys())

# Split into batches for MongoDB queries
batch_size = 800
batches = [all_article_ids[i:i+batch_size] for i in range(0, len(all_article_ids), batch_size)]

# Prepare batch queries
batch_queries = []
for batch in batches:
    query = {
        "collection": "articles",
        "filter": {"article_id": {"$in": batch}},
        "projection": {"article_id": 1, "title": 1, "description": 1}
    }
    batch_queries.append(query)

print('__RESULT__:')
print(json.dumps({
    'total_articles': len(all_article_ids),
    'batches': len(batch_queries),
    'first_batch_size': len(batches[0]) if batches else 0
}))"}

